patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 2fb60ef11499..dabf5695410f 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -516,9 +516,15 @@ bool InstCombinerImpl::SimplifyAssociativeOrCommutative(BinaryOperator &I) {
           // It simplifies to V.  Form "V op B".
           replaceOperand(I, 0, V);
           replaceOperand(I, 1, B);
+          bool IsNUW = hasNoUnsignedWrap(I) && hasNoUnsignedWrap(*Op0);
+          bool IsNSW = maintainNoSignedWrap(I, C, A) && hasNoSignedWrap(*Op0);
           // Conservatively clear the optional flags, since they may not be
           // preserved by the reassociation.
           ClearSubclassDataAfterReassociation(I);
+          if (IsNUW)
+            I.setHasNoUnsignedWrap(true);
+          if (IsNSW)
+            I.setHasNoSignedWrap(true);
           Changed = true;
           ++NumReassoc;
           continue;
@@ -536,9 +542,15 @@ bool InstCombinerImpl::SimplifyAssociativeOrCommutative(BinaryOperator &I) {
           // It simplifies to V.  Form "B op V".
           replaceOperand(I, 0, B);
           replaceOperand(I, 1, V);
+          bool IsNUW = hasNoUnsignedWrap(I) && hasNoUnsignedWrap(*Op1);
+          bool IsNSW = maintainNoSignedWrap(I, C, A) && hasNoSignedWrap(*Op1);
           // Conservatively clear the optional flags, since they may not be
           // preserved by the reassociation.
           ClearSubclassDataAfterReassociation(I);
+          if (IsNUW)
+            I.setHasNoUnsignedWrap(true);
+          if (IsNSW)
+            I.setHasNoSignedWrap(true);
           Changed = true;
           ++NumReassoc;
           continue;

