// Return true, if No Signed Wrap should be maintained for I.
// The No Signed Wrap flag can be kept if the reassociated operation preserves
// the no signed overflow guarantee. For Add/Sub, when reassociating to
// "A op (B op C)", this can be shown if constant-folding "B op C" does not
// overflow. For Mul, reassociation is safe if both the original instruction and
// the inner multiply are marked nsw because signed multiplication is
// associative under the precondition that all intermediate products are within
// range.
static bool maintainNoSignedWrap(BinaryOperator &I, Value *B, Value *C) {
  auto *OBO = dyn_cast<OverflowingBinaryOperator>(&I);
  if (!OBO || !OBO->hasNoSignedWrap())
    return false;

  // We reason about Add, Sub, and Mul only.
  Instruction::BinaryOps Opcode = I.getOpcode();
  if (Opcode == Instruction::Mul)
    return true;
  if (Opcode != Instruction::Add && Opcode != Instruction::Sub)
    return false;

  const APInt *BVal, *CVal;
  if (!match(B, m_APInt(BVal)) || !match(C, m_APInt(CVal)))
    return false;

  bool Overflow = false;
  if (Opcode == Instruction::Add)
    (void)BVal->sadd_ov(*CVal, Overflow);
  else
    (void)BVal->ssub_ov(*CVal, Overflow);

  return !Overflow;
}
